        easy_menu.Display_Char(CHAR_WIDTH, (SCREEN_HEIGHT / 2) - (CHAR_HEIGHT / 2), '[', 0);
        
        easy_menu.Display_Char(SCREEN_WIDTH - CHAR_WIDTH, (SCREEN_HEIGHT / 2) - (CHAR_HEIGHT / 2), ']', 0);
        
